class Solution:
    def snakesAndLadders(self, board):
        from collections import deque
        n = len(board)
        total = n * n
        def label_to_rc(label):
            idx = label - 1
            row_from_bottom = idx // n
            col = idx % n
            if row_from_bottom % 2 == 1:
                col = n - 1 - col
            r = n - 1 - row_from_bottom
            return r, col
        visited = {1}
        q = deque([(1, 0)])
        while q:
            curr, moves = q.popleft()
            for dice in range(1, 7):
                nxt = curr + dice
                if nxt > total:
                    break
                r, c = label_to_rc(nxt)
                if board[r][c] != -1:
                    nxt = board[r][c]
                if nxt == total:
                    return moves + 1
                if nxt not in visited:
                    visited.add(nxt)
                    q.append((nxt, moves + 1))
        return -1

