var snakesAndLadders = function(board) {
    const n = board.length;
    const total = n * n;
    function labelToRC(label) {
        const idx = label - 1;
        const rowFromBottom = Math.floor(idx / n);
        let col = idx % n;
        if (rowFromBottom % 2 === 1) col = n - 1 - col;
        const r = n - 1 - rowFromBottom;
        return [r, col];
    }
    const visited = new Set([1]);
    const queue = [[1, 0]];
    let head = 0;
    while (head < queue.length) {
        const [curr, moves] = queue[head++];
        for (let dice = 1; dice <= 6; dice++) {
            let nxt = curr + dice;
            if (nxt > total) break;
            const [r, c] = labelToRC(nxt);
            if (board[r][c] !== -1) nxt = board[r][c];
            if (nxt === total) return moves + 1;
            if (!visited.has(nxt)) {
                visited.add(nxt);
                queue.push([nxt, moves + 1]);
            }
        }
    }
    return -1;
};
